import { Component, computed, inject, OnInit, signal } from '@angular/core';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { GradebookService } from '../../../core/services/gradebook.service';
import { AuthService } from '../../../core/services/auth.service';
import { ToastService } from '../../../core/services/toast.service';
import { LearnerGradesDto } from '../../../core/models/gradebook.models';
import { CourseNavComponent } from '../../../shared/course-nav/course-nav';

/**
 * Student grades for a course — /courses/:courseId/grades.
 * Canvas-style: the learner's own scores across graded items (quizzes,
 * assignments) plus an overall total. Uses the existing per-learner gradebook
 * endpoint with the signed-in user's id.
 */
@Component({
  selector: 'app-grades',
  standalone: true,
  imports: [RouterLink, CourseNavComponent],
  template: `
    <div class="course-layout">
      <app-course-nav [courseId]="courseId()" active="grades" />

      <main class="course-main">
        <a [routerLink]="['/courses', courseId()]" class="back-link">
          <span class="material-icons">arrow_back</span> Back to course
        </a>

        @if (loading()) {
          <div class="loading-spinner"><div class="spinner"></div></div>
        } @else if (grades(); as g) {
          <div class="gr-head">
            <h1>Grades</h1>
            <div class="gr-summary">
              <div class="gr-overall">
                <span class="gr-overall-val">{{ g.overallScore !== null ? (g.overallScore + '%') : '—' }}</span>
                <span class="gr-overall-lbl">Overall</span>
              </div>
              <span class="badge" [class.badge-success]="g.completionStatus === 'Completed'"
                    [class.badge-gray]="g.completionStatus !== 'Completed'">
                {{ g.completionStatus }}
              </span>
            </div>
          </div>

          <div class="card">
            @if (g.items.length) {
              <table class="gr-table">
                <thead>
                  <tr><th>Item</th><th>Type</th><th class="gr-num">Score</th><th>Status</th><th>Graded</th></tr>
                </thead>
                <tbody>
                  @for (it of g.items; track $index) {
                    <tr>
                      <td class="gr-title">{{ it.title }}</td>
                      <td><span class="badge badge-gray">{{ it.type }}</span></td>
                      <td class="gr-num">
                        @if (it.score !== null) { {{ it.score }} / {{ it.maxPoints }} }
                        @else { <span class="gr-muted">— / {{ it.maxPoints }}</span> }
                      </td>
                      <td>{{ it.status }}</td>
                      <td class="gr-muted">{{ it.gradedAt ? it.gradedAt.slice(0, 10) : '—' }}</td>
                    </tr>
                  }
                </tbody>
              </table>
            } @else {
              <div class="empty-state"><span class="material-icons">grading</span>
                <p>No graded items yet. Scores will appear here as you complete quizzes and assignments.</p>
              </div>
            }
          </div>
        }
      </main>
    </div>
  `,
  styleUrl: './grades.scss',
})
export class GradesComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private gradebook = inject(GradebookService);
  private auth = inject(AuthService);
  private toast = inject(ToastService);

  readonly courseId = signal(0);
  readonly grades = signal<LearnerGradesDto | null>(null);
  readonly loading = signal(true);

  ngOnInit(): void {
    this.courseId.set(Number(this.route.snapshot.paramMap.get('courseId')));
    const userId = this.auth.currentUser()?.userId;
    if (!userId) { this.loading.set(false); return; }

    this.gradebook.getLearnerGrades(this.courseId(), userId).subscribe({
      next: g => { this.grades.set(g); this.loading.set(false); },
      error: (e: Error) => { this.loading.set(false); this.toast.error(`Failed to load grades: ${e.message}`); },
    });
  }
}
